/* =========================================================================
   UAT MODEL EXAM — APPLICATION LOGIC
   ========================================================================= */

/* ---------------------------------------------------------------------
   CONFIG — edit these three values before you deploy.
   --------------------------------------------------------------------- */
const CONFIG = {
  // Paste the URL you get after deploying apps-script.gs as a Web App.
  SHEET_WEBAPP_URL: "https://script.google.com/macros/s/AKfycbziZv9oQWWZ0MWDT7Cj6r3lMfzn1Ueuxfefn2iFS6SSwvCakN3CWAU6aK3dDdjORvWCgw/exec",
  // Paste a base64 data-URI for each logo, e.g. "data:image/png;base64,iVBOR..."
  AAU_LOGO_BASE64: "data:image/jpeg;base64,",
  CHANNEL_LOGO_BASE64: "data:image/jpeg;base64,",
  ENGLISH_SECONDS: 60 * 60,      // 60 minutes
  MATH_SECONDS: 90 * 60,         // 90 minutes
  LEAVE_WARN_AT: 3,
  LEAVE_RESTART_AT: 5,
};

const STORAGE_KEY = "uatModelExamState_v1";

/* ---------------------------------------------------------------------
   STATE
   --------------------------------------------------------------------- */
function defaultState() {
  return {
    registered: false,
    name: "", city: "", school: "",
    device: detectDevice(),
    currentPage: "intro",       // intro | english | transition | resting | math | results
    english: { answers: {}, index: 0, endTime: null, submitted: false, leaveCount: 0, score: null, restartedOnce:false },
    math:    { answers: {}, index: 0, endTime: null, submitted: false, leaveCount: 0, score: null, restartedOnce:false },
    rest:    { endTime: null, minutes: 15 },
    warnedAt3: { english:false, math:false },
    submittedToSheet: false,
  };
}

function detectDevice() {
  const w = window.innerWidth || document.documentElement.clientWidth;
  const ua = navigator.userAgent || "";
  const mobileUA = /Android|iPhone|iPad|iPod|Mobile/i.test(ua);
  return (w < 880 || mobileUA) ? "mobile" : "desktop";
}

let state = loadState();

function loadState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return defaultState();
    const parsed = JSON.parse(raw);
    // merge with defaults in case of schema changes
    return Object.assign(defaultState(), parsed);
  } catch (e) {
    return defaultState();
  }
}
function saveState() {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch (e) {}
}

/* ---------------------------------------------------------------------
   DOM HELPERS
   --------------------------------------------------------------------- */
const app = document.getElementById("app");
function el(tag, attrs = {}, ...children) {
  const e = document.createElement(tag);
  for (const [k, v] of Object.entries(attrs)) {
    if (k === "class") e.className = v;
    else if (k === "html") e.innerHTML = v;
    else if (k.startsWith("on") && typeof v === "function") e.addEventListener(k.slice(2), v);
    else e.setAttribute(k, v);
  }
  children.flat().forEach(c => {
    if (c === null || c === undefined) return;
    e.appendChild(typeof c === "string" ? document.createTextNode(c) : c);
  });
  return e;
}
function fmtTime(ms) {
  if (ms < 0) ms = 0;
  const total = Math.floor(ms / 1000);
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  const pad = n => String(n).padStart(2, "0");
  return h > 0 ? `${pad(h)}:${pad(m)}:${pad(s)}` : `${pad(m)}:${pad(s)}`;
}

function logoFrame(kind) {
  const src = kind === "aau" ? CONFIG.AAU_LOGO_BASE64 : CONFIG.CHANNEL_LOGO_BASE64;
  const cls = kind === "aau" ? "aau-frame" : "logo-frame";
  if (src) return el("div", { class: cls }, el("img", { src, alt: kind }));
  return el("div", { class: cls, html: `<span style="font-size:.6rem;font-weight:700;color:${kind==='aau'?'#0d2a4a':'#fff'}">${kind==='aau'?'AAU':'UAT'}</span>` });
}

function topbar() {
  return el("div", { class: "topbar" },
    el("div", { class: "brand-left" },
      logoFrame("channel"),
      el("div", { class: "brand-text" }, "UAT Model Exam", el("small", {}, "Prepared by @FreeUAT"))
    ),
    el("div", { class: "brand-right" }, logoFrame("aau"))
  );
}

function render() {
  app.innerHTML = "";
  app.appendChild(topbar());
  const wrap = el("div", { class: "screen" });
  switch (state.currentPage) {
    case "intro": wrap.appendChild(renderIntro()); break;
    case "english": wrap.appendChild(renderExam("english")); break;
    case "transition": wrap.appendChild(renderTransition()); break;
    case "resting": wrap.appendChild(renderResting()); break;
    case "math": wrap.appendChild(renderExam("math")); break;
    case "results": wrap.appendChild(renderResults()); break;
    default: wrap.appendChild(renderIntro());
  }
  app.appendChild(wrap);
  app.appendChild(el("div", { class: "footer-credit" }, "UAT Model Exam — Prepared by @FreeUAT"));
  startTickers();
}

/* ---------------------------------------------------------------------
   INTRO / REGISTRATION
   --------------------------------------------------------------------- */
function renderIntro() {
  const c = el("div", { class: "container" });

  if (state.device === "mobile") {
    c.appendChild(el("div", { class: "mobile-banner" },
      "📱 You are browsing on a phone. For the real UAT experience (full desktop layout, side navigation, timers exactly as on exam day), tap the ⋮ three-dot menu at the top-right of your browser and choose \"Desktop site.\""
    ));
  }

  c.appendChild(el("div", { class: "intro-hero" },
    el("div", { class: "eyebrow" }, "AAU ENTRANCE PRACTICE"),
    el("h1", {}, "UAT Model Exam 2"),
    el("p", { class: "muted" }, "A full-length practice test that mirrors the real University Aptitude Test experience.")
  ));

  c.appendChild(el("div", { class: "rest-note", style: "text-align:center;" },
    "📢 Join our official channel for updates and more model exams: ",
    el("a", { href: "https://t.me/UATEXAM_AAU", target: "_blank", style: "color:var(--navy); font-weight:700;" }, "@UATEXAM_AAU")
  ));

  const c1 = el("div", { class: "card" });
  c1.appendChild(el("h2", {}, "What this test contains"));
  c1.appendChild(el("div", { class: "info-grid" },
    el("div", { class: "info-box" }, el("div", { class: "num" }, "55"), el("div", { class: "lbl" }, "Verbal Reasoning (English) questions — 60 minutes")),
    el("div", { class: "info-box" }, el("div", { class: "num" }, "45"), el("div", { class: "lbl" }, "Quantitative Reasoning (Math) questions — 90 minutes"))
  ));
  c1.appendChild(el("p", { class: "small muted" }, "English begins first. When its 60-minute timer ends (or you submit), you'll move on to a short break screen before Math begins with its own fresh 90-minute timer."));
  c.appendChild(c1);

  const c2 = el("div", { class: "card" });
  c2.appendChild(el("h2", {}, "Allowed & not allowed"));
  c2.appendChild(el("ul", { class: "rules" },
    el("li", {}, el("strong", {}, "English section: "), "No calculators or external aids."),
    el("li", {}, el("strong", {}, "Math section: "), "A scientific calculator IS allowed — a calculator button is built into this test for you."),
    el("li", {}, "No other electronic devices, browser tabs, or outside help at any time."),
    el("li", {}, "Text on this page cannot be copied or selected."),
    el("li", {}, "Leaving this browser tab/window is tracked — see warning below.")
  ));
  c2.appendChild(el("div", { class: "rest-note" },
    "⚠️ Leaving the exam tab is monitored. After 3 exits you'll get a warning. After 5 exits, the current section restarts from Question 1 (your other, completed section is kept safe)."
  ));
  c.appendChild(c2);

  const c3 = el("div", { class: "card" });
  c3.appendChild(el("h2", {}, "Before you begin"));
  const nameField = el("div", { class: "field" }, el("label", {}, "Full name"), el("input", { id: "reg-name", type: "text", placeholder: "e.g. Netsanet Sisay", value: state.name || "" }));
  const cityField = el("div", { class: "field" }, el("label", {}, "City"), el("input", { id: "reg-city", type: "text", placeholder: "e.g. Addis Ababa", value: state.city || "" }));
  const schoolField = el("div", { class: "field" }, el("label", {}, "School"), el("input", { id: "reg-school", type: "text", placeholder: "e.g. Menelik II Secondary School", value: state.school || "" }));
  c3.appendChild(nameField);
  c3.appendChild(cityField);
  c3.appendChild(schoolField);

  const errBox = el("p", { class: "small", style: "color:var(--red); display:none;" });
  c3.appendChild(errBox);

  c3.appendChild(el("button", { class: "btn btn-primary btn-block", onclick: () => {
    const name = document.getElementById("reg-name").value.trim();
    const city = document.getElementById("reg-city").value.trim();
    const school = document.getElementById("reg-school").value.trim();
    if (!name || !city || !school) {
      errBox.textContent = "Please fill in your name, city, and school to continue.";
      errBox.style.display = "block";
      return;
    }
    state.name = name; state.city = city; state.school = school;
    state.registered = true;
    state.currentPage = "english";
    if (!state.english.endTime) state.english.endTime = Date.now() + CONFIG.ENGLISH_SECONDS * 1000;
    saveState();
    render();
  }}, "Begin English Section →"));

  c.appendChild(c3);
  return c;
}

/* ---------------------------------------------------------------------
   EXAM (shared renderer for english + math)
   --------------------------------------------------------------------- */
let mobileDrawerOpen = false;
let calcOpen = false;

function sectionData(section) {
  return section === "english"
    ? { list: ENGLISH_QUESTIONS, total: 55, label: "English — Verbal Reasoning", key: "english" }
    : { list: MATH_QUESTIONS, total: 45, label: "Math — Quantitative Reasoning", key: "math" };
}

function renderExam(section) {
  const sd = sectionData(section);
  const s = state[section];
  const q = sd.list[s.index];
  const wide = el("div", {});

  // ---- sticky exam top bar ----
  const topRow = el("div", { class: "exam-topbar" },
    el("div", { class: "section-label" }, sd.label, el("small", {}, `Question ${s.index + 1} of ${sd.total}`)),
    el("div", { style: "display:flex; align-items:center; gap:8px;" },
      state.device === "desktop" || true ? timerPillEl(section) : null,
      section === "math" ? el("button", { class: "nav-toggle-btn", onclick: () => { calcOpen = !calcOpen; renderCalcPanel(); } }, "🧮 Calculator") : null,
      state.device === "mobile" ? el("button", { class: "nav-toggle-btn", onclick: () => { mobileDrawerOpen = true; render(); } }, "☰ Menu") : null
    )
  );

  const body = el("div", { class: "exam-body" });

  // ---- main column ----
  const main = el("div", { class: "exam-main" });

  if (q.passage) {
    const p = PASSAGES[q.passage];
    main.appendChild(el("div", { class: "passage-panel" },
      el("h3", {}, p.title),
      el("div", { html: p.html })
    ));
  }

  const qCard = el("div", { class: "question-card" });
  qCard.appendChild(el("div", { class: "q-meta" },
    el("div", { class: "q-number" }, `Question ${q.id}`),
    el("div", { class: "q-mark" }, "Mark: 1.0")
  ));
  qCard.appendChild(el("div", { class: "q-text" }, q.text));

  const letters = ["A", "B", "C", "D"];
  q.options.forEach((opt, i) => {
    const selected = s.answers[q.id] === i;
    qCard.appendChild(el("div", {
      class: "option" + (selected ? " selected" : ""),
      onclick: () => { s.answers[q.id] = i; saveState(); render(); }
    },
      el("div", { class: "letter" }, letters[i]),
      el("div", { class: "opt-text" }, opt)
    ));
  });

  const navRow = el("div", { class: "q-nav-row" },
    el("button", { class: "btn btn-outline", disabled: s.index === 0 ? "disabled" : null, onclick: () => { s.index = Math.max(0, s.index - 1); saveState(); render(); } }, "← Previous"),
    el("button", { class: "btn btn-gold", onclick: () => { saveState(); flashSaved(); } }, "💾 Save Answer"),
    el("button", { class: "btn btn-primary", onclick: () => {
      if (s.index < sd.total - 1) { s.index++; saveState(); render(); }
      else { openSubmitConfirm(section); }
    }}, s.index < sd.total - 1 ? "Save & Next →" : "Review & Submit")
  );
  qCard.appendChild(navRow);
  main.appendChild(qCard);

  const submitBox = el("div", { class: "card", style: "margin-top:16px;" },
    el("button", { class: "btn btn-primary btn-block", onclick: () => openSubmitConfirm(section) }, `Submit ${section === "english" ? "English" : "Math"} Section`)
  );
  main.appendChild(submitBox);

  body.appendChild(main);

  // ---- side nav (desktop) ----
  if (state.device === "desktop") {
    body.appendChild(sideNavPanel(section));
  }

  wide.appendChild(topRow);
  wide.appendChild(body);

  // mobile drawer
  if (state.device === "mobile" && mobileDrawerOpen) {
    wide.appendChild(mobileDrawer(section));
  }
  // calculator
  if (section === "math" && calcOpen) {
    wide.appendChild(calcPanelEl());
  }
  // mobile calculator FAB
  if (state.device === "mobile" && section === "math") {
    wide.appendChild(el("div", { class: "mobile-fab-row" },
      el("button", { class: "fab calc", onclick: () => { calcOpen = !calcOpen; render(); } }, "🧮")
    ));
  }

  return wide;
}

function flashSaved() {
  const btn = [...document.querySelectorAll(".q-nav-row .btn-gold")][0];
  if (!btn) return;
  const original = btn.textContent;
  btn.textContent = "✓ Saved";
  setTimeout(() => { if (btn) btn.textContent = original; }, 900);
}

function sideNavPanel(section) {
  const sd = sectionData(section);
  const s = state[section];
  const panel = el("div", { class: "side-nav" });
  panel.appendChild(el("h4", {}, "Timer"));
  panel.appendChild(timerPillEl(section, true));
  panel.appendChild(el("h4", { style: "margin-top:16px;" }, "Question Navigator"));
  const grid = el("div", { class: "qgrid" });
  sd.list.forEach((qq, idx) => {
    const answered = s.answers[qq.id] !== undefined;
    grid.appendChild(el("button", {
      class: (answered ? "answered " : "") + (idx === s.index ? "current" : ""),
      onclick: () => { s.index = idx; saveState(); render(); }
    }, String(qq.id)));
  });
  panel.appendChild(grid);
  panel.appendChild(el("div", { class: "legend" },
    el("span", {}, el("span", { class: "dot answered" }), "Answered"),
    el("span", {}, el("span", { class: "dot unanswered" }), "Unanswered")
  ));
  panel.appendChild(el("div", { class: "submit-box" },
    el("button", { class: "btn btn-primary btn-block", onclick: () => openSubmitConfirm(section) }, "Submit Section")
  ));
  return panel;
}

function mobileDrawer(section) {
  const sd = sectionData(section);
  const s = state[section];
  const overlay = el("div", { class: "mobile-nav-drawer", onclick: (e) => { if (e.target === overlay) { mobileDrawerOpen = false; render(); } } });
  const panel = el("div", { class: "drawer-panel" });
  panel.appendChild(el("button", { class: "btn btn-outline btn-block", onclick: () => { mobileDrawerOpen = false; render(); } }, "Close ✕"));
  panel.appendChild(el("h4", { style: "margin-top:14px;" }, "Time Remaining"));
  panel.appendChild(timerPillEl(section, true));
  panel.appendChild(el("h4", { style: "margin-top:16px;" }, "Question Navigator"));
  const grid = el("div", { class: "qgrid" });
  sd.list.forEach((qq, idx) => {
    const answered = s.answers[qq.id] !== undefined;
    grid.appendChild(el("button", {
      class: (answered ? "answered " : "") + (idx === s.index ? "current" : ""),
      onclick: () => { s.index = idx; saveState(); mobileDrawerOpen = false; render(); }
    }, String(qq.id)));
  });
  panel.appendChild(grid);
  panel.appendChild(el("div", { class: "submit-box" },
    el("button", { class: "btn btn-primary btn-block", onclick: () => { mobileDrawerOpen = false; openSubmitConfirm(section); } }, "Submit Section")
  ));
  overlay.appendChild(panel);
  return overlay;
}

function timerPillEl(section, big) {
  const s = state[section];
  const remaining = Math.max(0, (s.endTime || Date.now()) - Date.now());
  const warn = remaining < 5 * 60 * 1000;
  return el("div", { class: "timer-pill" + (warn ? " warn" : ""), id: `timer-${section}`, style: big ? "font-size:1.3rem; text-align:center; margin-top:8px;" : "" }, fmtTime(remaining));
}

/* ---------------------------------------------------------------------
   SUBMIT CONFIRM MODAL
   --------------------------------------------------------------------- */
function openSubmitConfirm(section) {
  const sd = sectionData(section);
  const s = state[section];
  const answeredCount = Object.keys(s.answers).length;
  const overlay = el("div", { class: "modal-overlay" });
  const box = el("div", { class: "modal-box" },
    el("div", { class: "modal-icon" }, "📝"),
    el("h3", {}, `Submit ${section === "english" ? "English" : "Math"} Section?`),
    el("p", { class: "muted" }, `You have answered ${answeredCount} of ${sd.total} questions.`),
    el("div", { class: "btn-row", style: "justify-content:center;" },
      el("button", { class: "btn btn-outline", onclick: () => overlay.remove() }, "Keep Working"),
      el("button", { class: "btn btn-primary", onclick: () => { overlay.remove(); finalizeSection(section); } }, "Yes, Submit")
    )
  );
  overlay.appendChild(box);
  document.body.appendChild(overlay);
}

function finalizeSection(section) {
  const sd = sectionData(section);
  const s = state[section];
  if (s.submitted) return;
  let correct = 0;
  sd.list.forEach(q => { if (s.answers[q.id] === q.answer) correct++; });
  s.score = correct;
  s.submitted = true;
  saveState();

  if (section === "english") {
    state.currentPage = "transition";
  } else {
    state.currentPage = "results";
    submitScoreToSheet();
  }
  saveState();
  render();
}

/* ---------------------------------------------------------------------
   TRANSITION / REST
   --------------------------------------------------------------------- */
function renderTransition() {
  const c = el("div", { class: "container" });
  c.appendChild(el("div", { class: "card" },
    el("div", { class: "transition-icon" }, "✅"),
    el("h2", { class: "center" }, "English Section Complete"),
    el("p", { class: "center muted" }, `You answered ${Object.keys(state.english.answers).length} of 55 questions.`),
    el("p", { class: "center" }, "Ready for Math? It has 45 questions and a 90-minute timer, with a calculator available."),
    el("div", { class: "btn-row", style: "justify-content:center;" },
      el("button", { class: "btn btn-primary", onclick: () => {
        state.math.endTime = Date.now() + CONFIG.MATH_SECONDS * 1000;
        state.currentPage = "math";
        saveState(); render();
      }}, "Continue to Math Now →"),
      el("button", { class: "btn btn-outline", onclick: () => { showRestPicker(c); } }, "Take a Rest First")
    ),
    el("div", { id: "rest-picker-slot" })
  ));
  return c;
}

function showRestPicker(container) {
  const slot = document.getElementById("rest-picker-slot");
  if (!slot) return;
  slot.innerHTML = "";
  const valueLabel = el("div", { class: "rest-value" }, `${state.rest.minutes} min`);
  const slider = el("input", {
    type: "range", min: "10", max: "25", step: "1", value: String(state.rest.minutes),
    oninput: (e) => { state.rest.minutes = Number(e.target.value); valueLabel.textContent = `${state.rest.minutes} min`; }
  });
  slot.appendChild(el("h3", { style: "margin-top:18px;" }, "Choose your rest length"));
  slot.appendChild(el("div", { class: "rest-slider-row" }, slider, valueLabel));
  slot.appendChild(el("div", { class: "rest-note" }, "⏸️ This rest period is a feature of this practice tool only — it is not part of the real UAT exam."));
  slot.appendChild(el("button", { class: "btn btn-gold btn-block", style: "margin-top:14px;", onclick: () => {
    state.rest.endTime = Date.now() + state.rest.minutes * 60 * 1000;
    state.currentPage = "resting";
    saveState(); render();
  }}, "Start Rest"));
}

function renderResting() {
  const c = el("div", { class: "container" });
  const remaining = Math.max(0, state.rest.endTime - Date.now());
  c.appendChild(el("div", { class: "card center" },
    el("h2", {}, "Taking a Rest"),
    el("p", { class: "muted" }, "Relax — this pause is not part of the real UAT exam."),
    el("div", { class: "rest-countdown", id: "rest-countdown" }, fmtTime(remaining)),
    el("button", { class: "btn btn-primary", onclick: () => {
      state.math.endTime = Date.now() + CONFIG.MATH_SECONDS * 1000;
      state.currentPage = "math";
      saveState(); render();
    }}, "End Rest & Start Math Now")
  ));
  return c;
}

/* ---------------------------------------------------------------------
   RESULTS
   --------------------------------------------------------------------- */
function renderResults() {
  const c = el("div", { class: "container" });
  const eng = state.english.score ?? 0;
  const math = state.math.score ?? 0;
  const total = eng + math;
  const totalQ = 100;
  const pct = Math.round((total / totalQ) * 100);
  c.appendChild(el("div", { class: "card" },
    el("div", { class: "score-hero" },
      el("div", { class: "muted" }, `${state.name} — ${state.school}, ${state.city}`),
      el("div", { class: "score-big" }, `${total} / ${totalQ}`),
      el("div", { class: "score-sub" }, `Overall score: ${pct}%`)
    ),
    el("div", { class: "score-breakdown" },
      el("div", { class: "score-tile" }, el("div", { class: "n" }, `${eng} / 55`), el("div", { class: "l" }, "English")),
      el("div", { class: "score-tile" }, el("div", { class: "n" }, `${math} / 45`), el("div", { class: "l" }, "Math"))
    ),
    el("p", { class: "center muted small", style: "margin-top:20px;" }, "Your result has been recorded. Thank you for taking the UAT Model Exam.")
  ));

  c.appendChild(el("div", { class: "card center" },
    el("h3", {}, "Want more practice?"),
    el("p", { class: "muted small" },
      "Join our official channel for future model exams: ",
      el("a", { href: "https://t.me/UATEXAM_AAU", target: "_blank", style: "color:var(--navy); font-weight:700;" }, "@UATEXAM_AAU")
    ),
    el("p", { class: "muted small" },
      "Want to practice even more? Join our premium channel: ",
      el("a", { href: "https://t.me/NextGenUAT_Freshamn_bot", target: "_blank", style: "color:var(--gold); font-weight:700;" }, "@NextGenUAT_Freshamn_bot"),
      " or contact support: ",
      el("a", { href: "https://t.me/UAT_support", target: "_blank", style: "color:var(--gold); font-weight:700;" }, "@UAT_support")
    )
  ));

  return c;
}

/* ---------------------------------------------------------------------
   CALCULATOR
   --------------------------------------------------------------------- */
let calcExpr = "";
function renderCalcPanel() { render(); }
function calcPanelEl() {
  const screen = el("div", { class: "calc-screen", id: "calc-screen" }, calcExpr || "0");
  const buttons = ["7","8","9","÷","4","5","6","×","1","2","3","-","0",".","=","+","C","(",")","%"];
  const grid = el("div", { class: "calc-grid" });
  buttons.forEach(b => {
    const cls = "=" === b ? "eq" : ["÷","×","-","+","%"].includes(b) ? "op" : "";
    grid.appendChild(el("button", { class: cls, onclick: () => calcPress(b) }, b));
  });
  const clearBtn = el("button", { class: "clear", style:"grid-column:span 4; margin-top:6px; width:100%;", onclick: () => calcPress("C") }, "Clear");
  return el("div", { class: "calc-panel" },
    el("div", { style: "display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;" },
      el("strong", { style: "color:#fff; font-size:0.85rem;" }, "Calculator"),
      el("button", { style: "background:none;border:none;color:#fff;font-size:1rem;", onclick: () => { calcOpen = false; render(); } }, "✕")
    ),
    screen, grid, clearBtn
  );
}
function calcPress(b) {
  if (b === "C") { calcExpr = ""; }
  else if (b === "=") {
    try {
      const safe = calcExpr.replace(/×/g, "*").replace(/÷/g, "/").replace(/%/g, "/100");
      if (!/^[0-9+\-*/.() ]+$/.test(safe)) throw new Error("bad");
      // eslint-disable-next-line no-new-func
      const result = Function(`"use strict"; return (${safe})`)();
      calcExpr = String(Math.round(result * 1e8) / 1e8);
    } catch (e) { calcExpr = "Error"; }
  } else {
    if (calcExpr === "Error") calcExpr = "";
    calcExpr += b;
  }
  const scr = document.getElementById("calc-screen");
  if (scr) scr.textContent = calcExpr || "0";
}

/* ---------------------------------------------------------------------
   TICKERS: timers + rest countdown + auto-submit
   --------------------------------------------------------------------- */
let tickHandle = null;
function startTickers() {
  if (tickHandle) clearInterval(tickHandle);
  tickHandle = setInterval(() => {
    if (state.currentPage === "english" || state.currentPage === "math") {
      const s = state[state.currentPage];
      const remaining = (s.endTime || 0) - Date.now();
      const pill = document.getElementById(`timer-${state.currentPage}`);
      if (pill) {
        pill.textContent = fmtTime(Math.max(0, remaining));
        pill.classList.toggle("warn", remaining < 5 * 60 * 1000);
      }
      if (remaining <= 0 && !s.submitted) {
        finalizeSection(state.currentPage);
      }
    } else if (state.currentPage === "resting") {
      const remaining = state.rest.endTime - Date.now();
      const cd = document.getElementById("rest-countdown");
      if (cd) cd.textContent = fmtTime(Math.max(0, remaining));
      if (remaining <= 0) {
        state.math.endTime = Date.now() + CONFIG.MATH_SECONDS * 1000;
        state.currentPage = "math";
        saveState(); render();
      }
    }
  }, 500);
}

/* ---------------------------------------------------------------------
   ANTI-LEAVE DETECTION
   --------------------------------------------------------------------- */
document.addEventListener("visibilitychange", () => {
  if (document.hidden) handleLeave();
});

function handleLeave() {
  const section = state.currentPage;
  if (section !== "english" && section !== "math") return;
  const s = state[section];
  if (s.submitted) return;
  s.leaveCount = (s.leaveCount || 0) + 1;
  saveState();

  if (s.leaveCount === CONFIG.LEAVE_WARN_AT) {
    state._pendingWarn = section;
  }
  if (s.leaveCount >= CONFIG.LEAVE_RESTART_AT) {
    restartSection(section);
    state._pendingRestartNotice = section;
  }
  saveState();
}

function restartSection(section) {
  const s = state[section];
  s.answers = {};
  s.index = 0;
  s.leaveCount = 0;
  s.restartedOnce = true;
  if (section === "english") {
    s.endTime = Date.now() + CONFIG.ENGLISH_SECONDS * 1000;
  } else {
    s.endTime = Date.now() + CONFIG.MATH_SECONDS * 1000;
  }
  saveState();
}

function showLeaveModals() {
  if (state._pendingRestartNotice) {
    const section = state._pendingRestartNotice;
    state._pendingRestartNotice = null;
    saveState();
    const overlay = el("div", { class: "modal-overlay" },
      el("div", { class: "modal-box" },
        el("div", { class: "modal-icon" }, "🔄"),
        el("h3", {}, "Section Restarted"),
        el("p", {}, `You left the exam window 5 times, which isn't allowed. Your ${section === "english" ? "English" : "Math"} section has restarted from Question 1 with a fresh timer.`),
        el("button", { class: "btn btn-primary", onclick: (e) => e.target.closest(".modal-overlay").remove() }, "I Understand")
      )
    );
    document.body.appendChild(overlay);
    render();
    return;
  }
  if (state._pendingWarn) {
    const section = state._pendingWarn;
    state._pendingWarn = null;
    saveState();
    const overlay = el("div", { class: "modal-overlay" },
      el("div", { class: "modal-box" },
        el("div", { class: "modal-icon" }, "⚠️"),
        el("h3", {}, "Warning: Leaving the Exam"),
        el("p", {}, `You have left this window ${CONFIG.LEAVE_WARN_AT} times. Leaving is not allowed. If you leave ${CONFIG.LEAVE_RESTART_AT - CONFIG.LEAVE_WARN_AT} more time(s), your current section will restart from Question 1.`),
        el("button", { class: "btn btn-primary", onclick: (e) => e.target.closest(".modal-overlay").remove() }, "I Understand")
      )
    );
    document.body.appendChild(overlay);
  }
}

/* ---------------------------------------------------------------------
   ANTI-COPY
   --------------------------------------------------------------------- */
["copy", "cut", "contextmenu", "selectstart", "dragstart"].forEach(evt => {
  document.addEventListener(evt, (e) => { e.preventDefault(); return false; });
});
document.addEventListener("keydown", (e) => {
  const blocked = (e.ctrlKey || e.metaKey) && ["c", "x", "u", "s", "p"].includes(e.key.toLowerCase());
  const devtools = e.key === "F12" || ((e.ctrlKey || e.metaKey) && e.shiftKey && ["i", "j", "c"].includes(e.key.toLowerCase()));
  if (blocked || devtools) e.preventDefault();
});

/* ---------------------------------------------------------------------
   GOOGLE SHEET SUBMISSION
   --------------------------------------------------------------------- */
function submitScoreToSheet() {
  if (state.submittedToSheet) return;
  if (!CONFIG.SHEET_WEBAPP_URL || CONFIG.SHEET_WEBAPP_URL.indexOf("PASTE_YOUR") === 0) return;
  const payload = {
    timestamp: new Date().toISOString(),
    name: state.name, city: state.city, school: state.school,
    englishScore: state.english.score, englishTotal: 55,
    mathScore: state.math.score, mathTotal: 45,
    totalScore: (state.english.score || 0) + (state.math.score || 0),
    totalQuestions: 100,
    englishRestarted: state.english.restartedOnce,
    mathRestarted: state.math.restartedOnce,
    device: state.device,
  };
  fetch(CONFIG.SHEET_WEBAPP_URL, {
    method: "POST",
    mode: "no-cors",
    headers: { "Content-Type": "text/plain;charset=utf-8" },
    body: JSON.stringify(payload),
  }).catch(() => {});
  state.submittedToSheet = true;
  saveState();
}

/* ---------------------------------------------------------------------
   INIT
   --------------------------------------------------------------------- */
window.addEventListener("resize", () => { state.device = detectDevice(); });
render();
setTimeout(showLeaveModals, 300);
const modalCheck = setInterval(() => {
  if (state._pendingWarn || state._pendingRestartNotice) showLeaveModals();
}, 1000);
